import upload from '@/components/public/upload'
export default {
    components: {
        upload
    },
    data() {
        return {
            showDialog: false,
            form: {
                // 物流公司
                business: '',
                // 快递单号
                number: '',
                // 详细内容
                desc: ''
            },
            rules: {
                business: [{required: true, message: '请输入物流公司'}],
                number: [{required: true, message: "请输入快递单号"}],
            },
            fileList: []
        }
    },
    props: {
        value: {
            type: Boolean,
            default: false,
        },
        aid: {
            type: [String, Number],
            default: -1
        }
    },
    methods: {
        submitForm() {
            console.log(this.$refs)
            this.$refs['inputForm'].validate(async (valid) => {
                if(valid) {
                    let fileList = []
                    this.fileList.forEach(item => {
                        fileList.push(item.response.data);
                    })
                    let data = {
                        id: this.aid,
                        express_name: this.form.business,
                        invoice_no: this.form.number,
                        express_remark: this.form.desc,
                        express_image: fileList.length <= 0 ? '' : fileList[0].base_url
                    };
                    let res = await this.$post("after_sale/express", data);
                    if(res.code == 1) {
                        this.$message({
                            message: '提交成功',
                            type: 'success'
                        });
                        this.showDialog = false;
                        this.$emit("success")
                    }
                }
                else {
                    return false
                }
            })

        },
        uploadSuccess(e) {
            let fileList = Object.assign([], e);
            this.fileList = fileList;
        }
    },
    watch: {
        value(val) {
            this.showDialog = val;
        },
        showDialog(val) {
            this.$emit("input", val);
        },
    }
}
